// Validate payload
const body = $input.first().json.body || $input.first().json;
const required = ['streak_days', 'time_of_day', 'recent_mood', 'spiritual_layer'];
for (const k of required) {
  if (body[k] === undefined || body[k] === null) {
    throw new Error(`Missing required field: ${k}`);
  }
}
const ctx = {
  display_name: body.display_name ?? null,
  aliado_name: body.aliado_name ?? 'Aliado',
  streak_days: Number(body.streak_days) || 0,
  time_of_day: String(body.time_of_day),
  recent_mood: String(body.recent_mood).toLowerCase().trim(),
  spiritual_layer: Boolean(body.spiritual_layer),
  language: body.language ?? 'es'
};
if (!['manana','tarde','noche','madrugada'].includes(ctx.time_of_day)) {
  throw new Error('time_of_day must be manana|tarde|noche|madrugada');
}

// Crisis detection
const crisisKw = ['suicid','matarme','quitarme la vida','acabar con todo','no quiero seguir','hacerme dano','autolesion','cortarme','menor de edad','ninas','niñas','ninos','niños','abuso'];
const userMsg = String(body.user_message ?? '').toLowerCase().normalize('NFD').replace(/[\u0300-\u036f]/g,'');
const isCrisis = crisisKw.some(k => userMsg.includes(k.normalize('NFD').replace(/[\u0300-\u036f]/g,'')));

const systemPrompt = `Eres Aliado, un companero conversacional dentro de Antiport. La persona te habla justo antes de abrir un enlace bloqueado. Tu trabajo es estar ahi, escuchar y ofrecer una salida concreta en menos de 90 segundos.\n\nTono: directo, calido, sin juzgar. Frases cortas. Segunda persona. Maximo 60 palabras por mensaje.\n\nReglas duras:\n- Nunca uses: pecador, esclavo, sucio, verguenza, fracaso, cobarde, debil, perdido, campeon, guerrero, soldado.\n- Nunca describas contenido sexual.\n- Nunca minimices ("no pasa nada", "todos lo hacen").\n- Nunca moralices.\n- Si spiritual_layer=false: jamas menciones Dios, Biblia, oracion ni terminos religiosos.\n- Si spiritual_layer=true: puedes ofrecer UN versiculo o UNA oracion, una sola vez.\n- Si menciona suicidio, autolesion o menores: derivas a recursos clinicos.\n\nEstructura: pregunta abierta corta + UNA alternativa concreta + cierre breve.`;

const userPrompt = `Contexto:\n- Persona: ${ctx.display_name || '(anonimo, no uses nombre)'}\n- Te llaman: ${ctx.aliado_name}\n- Racha: ${ctx.streak_days} dias limpios\n- Hora del dia: ${ctx.time_of_day}\n- Estado emocional: ${ctx.recent_mood}\n- Capa espiritual activa: ${ctx.spiritual_layer ? 'si' : 'no'}\n\nLa persona acaba de intentar abrir un sitio bloqueado. Esta esperando tu primer mensaje.`;

return [{ json: { ctx, isCrisis, systemPrompt, userPrompt } }];

return [{ json: {
  text: 'Para. Lo que has dicho importa, y no es algo para resolver tu solo ahora mismo.

En Espana puedes llamar al 024 (linea de conducta suicida, gratis, 24 h) o al Telefono de la Esperanza 717 003 717.

Quieres que te abra el telefono ahora para llamar a alguien de tu lista? Sigo aqui.',
  source: 'crisis'
}}];

// Extract text + run guardrails
const body = $input.first().json.body || $input.first().json;
const raw = body?.choices?.[0]?.message?.content || $input.first().json?.choices?.[0]?.message?.content || '';
const text = String(raw).trim();
const ctx = $('Validate & Build Prompt').first().json.ctx;

const banned = ['pecador','esclavo','esclava','sucio','sucia','verguenza','fracaso','cobarde','no pasa nada','todos lo hacen','no es para tanto','campeon','guerrero','soldado'];
const spiritual = ['dios','jesus','cristo','biblia','espiritu santo','oracion','rezar','parroquia','iglesia','evangelio','salmo','versiculo'];
const norm = text.toLowerCase().normalize('NFD').replace(/[\u0300-\u036f]/g,'');

const fallbacks = [
  'Estoy aqui. Antes de decidir nada, respira conmigo cinco veces: 4 segundos dentro, 7 reteniendo, 8 fuera. Cuando termines, decides tu. Sin prisa.',
  'Para un segundo. Pon los dos pies en el suelo y describe en voz alta tres cosas que ves ahora mismo. Cuando acabes, hablamos.',
  'Sal del cuarto. Vete a la cocina, bebe un vaso de agua entero y vuelve. Te espero.',
  'Mira las anclas que subiste cuando estabas mas tranquilo. Las pusiste ahi tu, por algo. Abrelas antes de hacer nada mas.',
  'Esto que sientes va a bajar en 10 minutos hagas lo que hagas. Pon un timer, sal a la calle, vuelve y vemos si sigue ahi. Probamos?'
];

let violation = null;
for (const p of banned) if (norm.includes(p)) { violation = `banned:${p}`; break; }
if (!violation && !ctx.spiritual_layer) {
  for (const p of spiritual) if (norm.includes(p)) { violation = `spiritual:${p}`; break; }
}
const words = text.split(/\s+/).filter(Boolean).length;
if (!violation && words > 60) violation = 'too_long';
if (!violation && (words < 6 || !text)) violation = 'too_short';

if (violation) {
  const idx = Math.floor(Math.random() * fallbacks.length);
  return [{ json: { text: fallbacks[idx], source: 'fallback', reason: violation } }];
}
return [{ json: { text, source: 'llm' } }];
